<?php
declare(strict_types=1);
use Opus\Security\Acl\AclPolicy;use Opus\Security\Sso\LocalPasswordSsoProvider;use Opus\Security\Sso\SsoIdentity;use Opus\Security\Sso\SsoManager;
final class OwasysRuntimeSecurity { private AclPolicy $acl;private SsoManager $sso;public function __construct(private readonly string $siteRoot){$this->acl=new AclPolicy($siteRoot.'/config/acl.json');$this->sso=new SsoManager([new LocalPasswordSsoProvider($siteRoot.'/var/auth/local-users.json')]);} public function authenticate(array $post):SsoIdentity{return $this->sso->authenticate((string)($post['owasys_sso_provider']??'local-password'),['username'=>(string)($post['owasys_username']??''),'password'=>(string)($post['owasys_password']??'')]);} public function assertAllowed(?array $identity,string $resource,string $action='open'):void{$roles=is_array($identity['roles']??null)?$identity['roles']:[];$d=$this->acl->decide($roles,$resource,$action);if(!$d->allowed)throw new RuntimeException($d->code.':'.$resource.':'.$action);} }
